using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<TicketClassifierService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public TicketClassifierService(ILogger<TicketClassifierService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public (ITransformer model, EvaluationMetricsResponse metrics) TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);

        var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with {Path}", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);

        var perClass = metrics.PerClassLogLoss
            .Select((_, i) => new PerClassMetric
            {
                Class = metrics.ConfusionMatrix.PredictedClassesIndicators[i],
                Precision = metrics.ConfusionMatrix.PerClassPrecision[i],
                Recall = metrics.ConfusionMatrix.PerClassRecall[i],
                F1Score = 2 * (metrics.ConfusionMatrix.PerClassPrecision[i] * metrics.ConfusionMatrix.PerClassRecall[i])
                    / (metrics.ConfusionMatrix.PerClassPrecision[i] + metrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
            }).ToArray();

        var response = new EvaluationMetricsResponse
        {
            MacroAccuracy = (float)metrics.MacroAccuracy,
            MicroAccuracy = (float)metrics.MicroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = perClass
        };

        return (model, response);
    }

    public string ModelPath => _modelPath;
}

