1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class TicketClassifierService
8. {
9.     private readonly MLContext _mlContext;
10.     private readonly ILogger<TicketClassifierService> _logger;
11.     private readonly string _dataPath;
12.     private readonly string _modelPath;
13. 
14.     public TicketClassifierService(ILogger<TicketClassifierService> logger, IWebHostEnvironment env)
15.     {
16.         _mlContext = new MLContext(seed: 42);
17.         _logger = logger;
18.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
19.         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
20.     }
21. 
22.     public (ITransformer model, EvaluationMetricsResponse metrics) TrainAndEvaluate()
23.     {
24.         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
25.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
26. 
27.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);
28. 
29.         var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
30.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
31.             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
32.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
33.             .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
34.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
35.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
36. 
37.         _logger.LogInformation("Training model with {Path}", _dataPath);
38.         var model = pipeline.Fit(split.TrainSet);
39. 
40.         var predictions = model.Transform(split.TestSet);
41.         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
42. 
43.         _logger.LogInformation(
44.             "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
45.             metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);
46. 
47.         _mlContext.Model.Save(model, data.Schema, _modelPath);
48.         _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
49. 
50.         var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
51.         predictions.Schema["Label"].GetKeyValues(ref labelBuffer);
52.         var labels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
53. 
54.         var perClass = labels
55.             .Select((label, i) => new PerClassMetric
56.             {
57.                 Class = label,
58.                 Precision = metrics.ConfusionMatrix.PerClassPrecision[i],
59.                 Recall = metrics.ConfusionMatrix.PerClassRecall[i],
60.                 F1Score = 2 * (metrics.ConfusionMatrix.PerClassPrecision[i] * metrics.ConfusionMatrix.PerClassRecall[i])
61.                     / (metrics.ConfusionMatrix.PerClassPrecision[i] + metrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
62.             }).ToArray();
63. 
64.         var response = new EvaluationMetricsResponse
65.         {
66.             MacroAccuracy = (float)metrics.MacroAccuracy,
67.             MicroAccuracy = (float)metrics.MicroAccuracy,
68.             LogLoss = (float)metrics.LogLoss,
69.             LogLossReduction = (float)metrics.LogLossReduction,
70.             PerClassMetrics = perClass
71.         };
72. 
73.         return (model, response);
74.     }
75. 
76.     public string ModelPath => _modelPath;
77. }
